('11c66ce6-3fcd-46c3-927d-d4f6133d159a','Ög 113',NULL,58.4212,15.6327,': uerun : let : resa : sten : þena : eftiʀ : bofa : sun : sin : aouk : eftiʀ : eskerþi : totur sina kuþ : hiulbi : seol : þeʀa','"Værun let ræisa stæin þenna æftiʀ "Bofa, sun sinn, ok æftiʀ "Æsgærði, dottur sina. "Guð hialpi sial þæiʀa.',NULL,'Vérún had this stone raised in memory of Bófi, her son, and in memory of Ásgerðr, her daughter. May God help their souls.',NULL,NULL,'Runsten','Sten','Östergötland','Sweden'),
('2b00333f-d4a9-4a92-9a14-d92f4a05dc48','Ög Hov28;26',NULL,58.3788,14.9181,'…k × tul…','… …',NULL,'…',NULL,NULL,'Fragment av gravhäll, liggande häll/lockhäll','Kalksten','Östergötland','Sweden')
